import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const cardVariants = cva(
  "rounded-xl border bg-card text-card-foreground transition-all duration-200",
  {
    variants: {
      elevation: {
        none: "shadow-none",
        sm: "shadow-sm",
        md: "shadow",
        lg: "shadow-lg",
        xl: "shadow-xl",
        "2xl": "shadow-2xl",
      },
      variant: {
        default: "",
        gradient: "border-primary/20 bg-gradient-to-br from-card to-accent/5",
      },
      isHoverable: {
        true: "hover:shadow-md hover:-translate-y-0.5 cursor-pointer",
        false: "",
      }
    },
    defaultVariants: {
      elevation: "md",
      variant: "default",
      isHoverable: false,
    },
  }
)

export interface CardProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, elevation, variant, isHoverable, ...props }, ref) => (
    <div
      ref={ref}
      className={cn(cardVariants({ elevation, variant, isHoverable }), className)}
      {...props}
    />
  )
)
Card.displayName = "Card"

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex flex-col space-y-1.5 p-6", className)}
    {...props}
  />
))
CardHeader.displayName = "CardHeader"

